def count_unreachable(spec: dict) -> int:
    """Count graph nodes that can never be reached from start."""
    adj = spec["adj"]; start = spec["start"]
    everyone = set(adj.keys())
    for outs in adj.values():
        for t in outs:
            everyone.add(t)
    seen = set(); stack = [start]
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        stack.extend(adj.get(n, []))
    return len(everyone) - len(seen)

