def hops_between(spec: dict) -> int:
    """Shortest hop count from start to goal, or -1 when unreachable."""
    adj = spec["adj"]; start = spec["start"]; goal = spec["goal"]
    dist = {start: 0}; queue = [start]
    while queue:
        n = queue.pop(0)
        if n == goal:
            return dist[n]
        for t in adj.get(n, []):
            if t not in dist:
                dist[t] = dist[n] + 1
                queue.append(t)
    return -1

