def count_within_hops(spec: dict) -> int:
    """Count nodes lying within limit hops of start."""
    adj = spec["adj"]; limit = spec["limit"]
    dist = {spec["start"]: 0}; queue = [spec["start"]]; total = 0
    while queue:
        n = queue.pop(0)
        total += 1
        if dist[n] < limit:
            for t in adj.get(n, []):
                if t not in dist:
                    dist[t] = dist[n] + 1
                    queue.append(t)
    return total

