def count_ancestors(spec: dict) -> int:
    """Count nodes that can reach target via directed edges, target excluded."""
    adj = spec["adj"]; target = spec["target"]
    rev = {}
    for src in adj:
        rev.setdefault(src, [])
        for dst in adj[src]:
            rev.setdefault(dst, []).append(src)
    seen = set(); stack = [target]
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        stack.extend(rev.get(n, []))
    return len(seen) - 1

